   */
  onItemAdded: (value: string, label: ReactNode) => void;
}
/**
 * Description placeholder
 * @author Adminbot
 *
 * @type {*}
 */
const MultiSelectContext = createContext<MultiSelectContextType | null>(null);

/**
 * Description placeholder
 * @author Adminbot
 *
 * @export
 * @param {{
 *   children: ReactNode;
 *   values?: string[];
 *   defaultValues?: string[];
 *   onValuesChange?: (values: string[]) => void;
 *   single?: boolean;
 * }} param0
 * @param {ReactNode} param0.children
 * @param {{}} param0.defaultValues
 * @param {(values: {}) => void} param0.onValuesChange
 * @param {boolean} [param0.single=false]
 * @param {{}} param0.values
 * @returns {void; single?: boolean; }) => ReactJSX.Element}
 */
export function MultiSelect({
  children,
  defaultValues,
  onValuesChange,
  single = false,
  values,
}: {
  children: ReactNode;
  values?: string[];
  defaultValues?: string[];
  onValuesChange?: (values: string[]) => void;
  single?: boolean;
}) {
  const [open, setOpen] = useState(false);
  const [internalValues, setInternalValues] = useState(
    new Set<string>(values ?? defaultValues),
  );
  const selectedValues = values ? new Set(values) : internalValues;
  const [items, setItems] = useState<Map<string, ReactNode>>(new Map());

  function toggleValue(value: string) {
    const getNewSet = (prev: Set<string>) => {
      if (single) {
        return prev.has(value) ? new Set<string>() : new Set<string>([value]);
      }
      const newSet = new Set(prev);
      if (newSet.has(value)) {
        newSet.delete(value);
      } else {
        newSet.add(value);
      }
      return newSet;
    };
    setInternalValues(getNewSet);
    onValuesChange?.([...getNewSet(selectedValues)]);
    if (single) setOpen(false);
  }

  const onItemAdded = useCallback((value: string, label: ReactNode) => {
    setItems((prev) => {
      if (prev.get(value) === label) return prev;
      return new Map(prev).set(value, label);
    });
  }, []);

  return (
    <MultiSelectContext
      value={{
        items,
        onItemAdded,
        open,
        selectedValues,
        setOpen,
        single,
        toggleValue,
      }}
    >
      <Popover open={open} onOpenChange={setOpen} modal={true}>
        {children}
      </Popover>
    </MultiSelectContext>
  );
}

