  discovered: DiscoveryRecord[],
) {
  const set = new Set(existing.map((s) => s.toLowerCase()));
  const merged = existing.slice();
  for (const d of discovered) {
    if (!set.has(d.name.toLowerCase())) {
      merged.push(d.name);
      set.add(d.name.toLowerCase());
    }
  }
  return merged;
}

/**
 * Description placeholder
 * @author Adminbot
 *
 * @export
 * @param {string} catalogPath
 * @returns {string[]}
 */
export function readCatalog(catalogPath: string) {
  const txt = fs.readFileSync(catalogPath, "utf8");
  const obj = JSON.parse(txt);
  return obj.mcpServers as string[];
}

/**
 * Description placeholder
 * @author Adminbot
 *
 * @export
 * @param {string} catalogPath
 * @param {string[]} servers
 * @returns {string}
 */
export function writeCatalog(catalogPath: string, servers: string[]) {
  // Compatibility shim: use atomicWriteCatalog when available
  const tmpPath = `${catalogPath}.tmp.${Date.now()}`;
  const out = { generatedAt: new Date().toISOString(), mcpServers: servers };
  fs.writeFileSync(tmpPath, JSON.stringify(out, null, 2) + "\n", "utf8");
  const backup = atomicWriteCatalog(tmpPath, catalogPath);
  return backup;
}

/**
 * Description placeholder
 * @author Adminbot
 *
 * @export
 * @param {string} tmpPath
 * @param {string} finalPath
 * @returns {string}
 */
export function atomicWriteCatalog(tmpPath: string, finalPath: string) {
  // Backup existing
  const backup = `${finalPath}.bak.${Date.now()}`;
  if (fs.existsSync(finalPath)) fs.copyFileSync(finalPath, backup);
  // Move tmp to final (atomic on most platforms)
  fs.renameSync(tmpPath, finalPath);
  return backup;
}

/**
 * Description placeholder
 * @author Adminbot
 *
 * @export
 * @param {{ name: string; cmd: string }[]} commands
 * @param {?{ timeout?: number }} [opts]
 * @returns {{}}
 */
export function runValidations(
  commands: { name: string; cmd: string }[],
  opts?: { timeout?: number },
) {
  const results: { name: string; ok: boolean; output: string }[] = [];
  for (const c of commands) {
    try {
      const out = execSync(c.cmd, {
        encoding: "utf8",
        stdio: ["pipe", "pipe", "pipe"],
        timeout: opts?.timeout ?? 120000,
      });
      results.push({
        name: c.name,
        ok: true,
        output: String(out).slice(0, 20000),
      });
    } catch (err: any) {
      const out = (err.stdout ?? err.message ?? String(err)).toString();
      results.push({ name: c.name, ok: false, output: out.slice(0, 20000) });
    }
  }
  return results;
}

/**
 * Description placeholder
 * @author Adminbot
 *
 * @export
 * @param {string} backupPath
 * @param {string} finalPath
 * @returns {{ restored: string; safetyCopy: string; }}
 */
export function rollbackRestore(backupPath: string, finalPath: string) {
  if (!fs.existsSync(backupPath))
    throw new Error(`Backup not found: ${backupPath}`);
  // Make a safety copy of current finalPath
  const safety = `${finalPath}.pre-rollback.${Date.now()}`;
  if (fs.existsSync(finalPath)) fs.copyFileSync(finalPath, safety);
  fs.copyFileSync(backupPath, finalPath);
  return { restored: finalPath, safetyCopy: safety };
}

/**
 * Description placeholder
 * @author Adminbot
 *
 * @export
 * @param {string} dir
 * @param {number} olderThanDays
 * @returns {{}}
 */
export function pruneBackups(dir: string, olderThanDays: number) {
  const deleted: string[] = [];
  if (!fs.existsSync(dir)) return deleted;
  const files = fs.readdirSync(dir);
  const now = Date.now();
  const cutoff = now - olderThanDays * 24 * 60 * 60 * 1000;
  for (const f of files) {
    if (f.includes(".bak.")) {
      const full = path.join(dir, f);
      try {
        const stat = fs.statSync(full);
        if (stat.mtimeMs < cutoff) {
          fs.unlinkSync(full);
          deleted.push(full);
        }
      } catch {
        // ignore
      }
    }
  }
  return deleted;
}

// Minimal helper template generator
/**
 * Description placeholder
 * @author Adminbot
 *
 * @export
 * @param {string} serverName
 * @param {string} helpersDir
 * @returns {{ path: any; written: boolean; }}
 */
export function generateHelper(serverName: string, helpersDir: string) {
  const fileName = path.join(helpersDir, `${serverName}.ts`);
  const content = `// Generated helper for ${serverName}\n// GeneratedAt: ${new Date().toISOString()}\nexport const name = '${serverName}';\n`;
  if (!fs.existsSync(helpersDir)) fs.mkdirSync(helpersDir, { recursive: true });
  if (fs.existsSync(fileName)) {
    const existing = fs.readFileSync(fileName, "utf8");
    if (existing === content) return { path: fileName, written: false };
  }
  fs.writeFileSync(fileName, content, "utf8");
  return { path: fileName, written: true };
}

/**
 * Description placeholder
 * @author Adminbot
 *
 * @export
 * @param {string[]} oldList
 * @param {string[]} newList
 * @returns {{ added: any; removed: any; }}
 */
export function diffLists(oldList: string[], newList: string[]) {
  const oldSet = new Set(oldList);
  const newSet = new Set(newList);
  const added = newList.filter((s) => !oldSet.has(s));
  const removed = oldList.filter((s) => !newSet.has(s));
  return { added, removed };
}

#!/usr/bin/env node
import { execSync } from "child_process";
import fs from "fs";
import path from "path";
import readline from "readline";
import yargs from "yargs";
import { hideBin } from "yargs/helpers";

import {
  diffLists,
  generateHelper,
  mergeCatalog,
  parseDockerPsOutput,
  parseGatewayOutput,
  pruneBackups,
  readCatalog,
  rollbackRestore,
  runValidations,
  writeCatalog,
} from "./mcp-runner-lib";

/**
 * Description placeholder
 * @author Adminbot
 *
 * @async
 * @returns {*}
 */
export async function main() {
  const argv = await yargs(hideBin(process.argv))
    .option("dry-run", { default: true, type: "boolean" })
    .option("apply", { default: false, type: "boolean" })
    .option("prune", { default: false, type: "boolean" })
    .option("force", { default: false, type: "boolean" })
    .option("rollback", { default: false, type: "boolean" })
    .option("backup", { default: "", type: "string" })
    .option("helpers-dir", { default: ".opencode/mcp-helpers", type: "string" })
    .option("catalog-path", {
      default: ".opencode/mcp_servers.json",
      type: "string",
    })
    .option("verbose", { default: false, type: "boolean" })
    .option("list", { default: false, type: "boolean" })
    .option("verify-only", { default: false, type: "boolean" }).argv;

  const catalogPath = path.resolve(argv["catalog-path"] as string);
  const helpersDir = path.resolve(argv["helpers-dir"] as string);

  if (!fs.existsSync(catalogPath)) {
    console.error("Catalog not found:", catalogPath);
    process.exit(2);
  }

  const existing = readCatalog(catalogPath);

  if (argv["list"]) {
    // Print newline-separated server names
    for (const s of existing) console.log(s);
    process.exit(0);
  }

  // --verify-only handled after discoveryRecords are collected

  // Attempt gateway discovery first, capture outputs for audit
  let gatewayOut = "";
  let dockerPsOut = "";
  const discoveryRecords = [] as any[];
  try {
    gatewayOut = execSync("docker mcp gateway run --profile adminbot", {
      encoding: "utf8",
      stdio: ["pipe", "pipe", "pipe"],
    });
    if (gatewayOut) {
      const r = parseGatewayOutput(gatewayOut);
      discoveryRecords.push(...r);
    }
  } catch {
    if (argv.verbose)
      console.warn("gateway discovery failed, falling back to docker ps");
  }

  if (discoveryRecords.length === 0) {
    try {
      dockerPsOut = execSync("docker ps --format '{{.Names}}'", {
        encoding: "utf8",
        stdio: ["pipe", "pipe", "pipe"],
      });
      if (dockerPsOut) {
        const r = parseDockerPsOutput(dockerPsOut);
        discoveryRecords.push(...r);
      }
    } catch (e: any) {
      if (argv.verbose) console.warn("docker ps failed: ", e?.message ?? e);
    }
  }

  const merged = mergeCatalog(existing, discoveryRecords);
  const d = diffLists(existing, merged);

  if (argv["verify-only"]) {
    const discoveredOnly = discoveryRecords.map((r) => r.name);
    const diff = diffLists(existing, discoveredOnly);
    console.log(JSON.stringify(diff, null, 2));
    process.exit(diff.added.length || diff.removed.length ? 2 : 0);
  }

  console.warn("Dry-run: proposed changes:");
  console.warn(JSON.stringify(d, null, 2));

  if (!argv.apply) {
    console.log("Run with --apply to make changes (default is dry-run)");
    return;
  }

  // Rollback path (if requested)
  if (argv["rollback"]) {
    const backupPath = argv["backup"] as string;
    if (!backupPath) {
      console.error("--rollback requires --backup <path>");
      process.exit(2);
    }
    try {
      const res = rollbackRestore(backupPath, catalogPath);
      console.log("Restored backup:", backupPath, "->", catalogPath);
      // run validations after restore
      const validationCommands = [
        { cmd: "npm run format", name: "format" },
        { cmd: "npm run type-check", name: "type-check" },
        { cmd: "npm run lint:strict", name: "lint-strict" },
        { cmd: "npm run verify:rules", name: "verify-rules" },
        { cmd: "npm run test:browser", name: "test-browser" },
      ];
      const valResults = runValidations(validationCommands, {
        timeout: 10 * 60 * 1000,
      });
      console.log(
        "Post-restore validations:",
        JSON.stringify(valResults, null, 2),
      );
      process.exit(0);
    } catch (err: any) {
      console.error("Rollback failed:", err?.message ?? String(err));
      process.exit(1);
    }
  }

  // Interactive confirmation unless --force
  if (!argv.force) {
    const rl = readline.createInterface({
      input: process.stdin,
      output: process.stdout,
    });
    const answer = await new Promise<string>((res) =>
      rl.question("Type APPLY to confirm writing changes: ", (ans: string) => {
        rl.close();
        res(ans);
      }),
    );
    if (answer.trim() !== "APPLY") {
      console.log("Aborted by user");
      return;
    }
  } else {
    // If running non-interactive force, require RUN_MCP_FORCE env flag
    if (!process.env.RUN_MCP_FORCE || process.env.RUN_MCP_FORCE !== "true") {
      console.error(
        "Non-interactive --force requires environment variable RUN_MCP_FORCE=true",
      );
      process.exit(3);
    }
  }

  console.warn("Applying changes...");

  // Prepare audit artifact
  const audit: any = {
    commands: {
      dockerPs: dockerPsOut ? dockerPsOut.slice(0, 20000) : null,
      gateway: gatewayOut ? gatewayOut.slice(0, 20000) : null,
    },
    files: { backups: [], written: [] },
    flags: argv,
    timestamp: new Date().toISOString().replaceAll(/[:.]/g, ""),
    validations: [],
  };

  // Write catalog (backup created by writeCatalog)
  const backup = writeCatalog(catalogPath, merged);
  audit.files.backups.push(backup);

  // Generate helpers
  for (const s of merged) {
    const out = generateHelper(s, helpersDir);
    if (out.written) audit.files.written.push(out.path);
  }

  // Run post-apply validations using helper
  const validationCommands = [
    { cmd: "npm run format", name: "format" },
    { cmd: "npm run type-check", name: "type-check" },
    { cmd: "npm run lint:strict", name: "lint-strict" },
    { cmd: "npm run verify:rules", name: "verify-rules" },
    { cmd: "npm run test:browser", name: "test-browser" },
  ];

  const valResults = runValidations(validationCommands, {
    timeout: 10 * 60 * 1000,
  });
  audit.validations.push(...valResults);
  for (const v of valResults) {
    if (argv.verbose) console.log(`${v.name} ${v.ok ? "passed" : "failed"}`);
    if (!v.ok) console.error(`${v.name} failed (see audit)`);
  }

  // Save audit file
  const auditDir = path.resolve(".opencode/mcp-audit");
  if (!fs.existsSync(auditDir)) fs.mkdirSync(auditDir, { recursive: true });
  const auditPath = path.join(
    auditDir,
    `mcp-runner-apply-${audit.timestamp}.json`,
  );
  fs.writeFileSync(auditPath, JSON.stringify(audit, null, 2), "utf8");
  console.log("Wrote audit artifact:", auditPath);

  // Prune backups older than 365 days by default (no-op if none)
  try {
    const pruned = pruneBackups(path.dirname(catalogPath), 365);
    if (pruned.length && argv.verbose) console.log("Pruned backups:", pruned);
  } catch (e) {
    if (argv.verbose)
      console.warn("Prune backups failed:", (e as any)?.message ?? e);
  }
}

main().catch((err) => {
  console.error(err);
  process.exit(1);
});

#!/usr/bin/env node
import { execSync } from "child_process";
import fs from "fs";
import path from "path";

/**
 * Description placeholder
 * @author Adminbot
 *
 * @param {string} [base="origin/main"]
 * @returns {*}
 */
function gitDiffFiles(base = "origin/main") {
  const out = execSync(`git diff --name-only ${base} --`).toString();
  return out.split(/\r?\n/).filter(Boolean);
}

/**
 * Description placeholder
 * @author Adminbot
 *
 * @param {string[]} files
 * @returns {*}
 */
function expandOneLevel(files: string[]) {
  // Simple heuristic: find files that reference these files by scanning for literal strings
  const allFiles = execSync("git ls-files")
    .toString()
    .split(/\r?\n/)
    .filter(Boolean);
  const dependents = new Set<string>();
  for (const f of allFiles) {
    try {
      const content = fs.readFileSync(f, "utf-8");
      for (const changed of files) {
        // Normalize changed path to posix form for matching
        const changedPosix = changed.replaceAll("\\", "/");
        const withoutExt = changedPosix.replace(/\.(tsx?|jsx?|json|xml)$/, "");
        const variants = [
          changedPosix,
          `./${changedPosix}`,
          withoutExt,
          `@/${changedPosix}`,
          `@/${withoutExt}`,
        ];

        // Look for import/from patterns or any occurrence of the variant string
        let matched = false;
        for (const v of variants) {
          if (
            content.includes(`from "${v}"`) ||
            content.includes(`from '${v}'`) ||
            content.includes(v)
          ) {
            matched = true;
            break;
          }
        }

        if (matched) dependents.add(f);
      }
    } catch {
      // skip non-text
    }
  }
  return Array.from(dependents);
}

/**
 * Description placeholder
 * @author Adminbot
 *
 * @param {string[]} changed
 * @returns {*}
 */
function mapFilesToPages(changed: string[]) {
  const pages = new Set<string>();
  for (const f of changed) {
    if (f.startsWith("app/")) {
      const parts = f.split(path.posix.sep);
      // app/(root)/dashboard/page.tsx -> dashboard
      if (parts.length > 2) pages.add(parts[2]);
    }
    if (f.startsWith("components/")) {
      const parts = f.split(path.posix.sep);
      if (parts[1] === "layouts" || parts[1] === "home") pages.add("home");
    }
  }
  return Array.from(pages);
}

/**
 * Description placeholder
 * @author Adminbot
 */
function main() {
  const args = process.argv.slice(2);
  const dryRun = args.includes("--dry-run");
  const baseIdx = args.indexOf("--diff-base");
  const base = baseIdx >= 0 ? args[baseIdx + 1] : "origin/main";

  const changed = gitDiffFiles(base);
  console.warn("Changed files:", changed);

  const expanded = expandOneLevel(changed);
  console.warn("One-level dependents:", expanded);

  const pages = mapFilesToPages([...changed, ...expanded]);
  console.warn("Affected pages:", pages);

  if (dryRun) {
    console.log(
      JSON.stringify({ changed: changed.length, ok: true, pages }, null, 2),
    );
    return;
  }

  // TODO: map to exact tests and run targeted test runner
  console.log("Run targeted tests for:", pages.join(", "));
}

if (require.main === module) main();

#!/usr/bin/env tsx
import { execSync } from "child_process";
import fs from "fs";
import { globby } from "globby";
import inquirer from "inquirer";
import path from "path";

/**
 * Description placeholder
 * @author Adminbot
 *
 * @type {*}
 */
const CMD = process.argv[1];

/**
 * Description placeholder
 * @author Adminbot
 *
 * @interface PlanCandidate
 * @typedef {PlanCandidate}
 */
interface PlanCandidate {
  /**
   * Description placeholder
   * @author Adminbot
   *
   * @type {string}
   */
  file: string;
  /**
   * Description placeholder
   * @author Adminbot
   *
   * @type {?string}
   */
  title?: string;
  /**
   * Description placeholder
   * @author Adminbot
   *
   * @type {?string}
   */
  goals?: string;
  /**
   * Description placeholder
   * @author Adminbot
   *
   * @type {?string[]}
   */
  targetFiles?: string[];
  /**
   * Description placeholder
   * @author Adminbot
   *
   * @type {?number}
   */
  score?: number;
}

/**
 * Description placeholder
 * @author Adminbot
 *
 * @export
 * @param {string} p
 * @returns {{
 *   title?: string;
 *   goals?: string;
 *   targetFiles?: string[];
 * }}
 */
export function readPlanFile(p: string): {
  title?: string;
  goals?: string;
  targetFiles?: string[];
} {
  const txt = fs.readFileSync(p, "utf8");
  const lines = txt.split(/\r?\n/);
  let title: string | undefined;
  let goals = "";
  let targetFiles: string[] = [];
  let inGoals = false;
  for (const l of lines) {
    if (!title && l.startsWith("# ")) title = l.replace(/^#\s*/, "").trim();
    if (l.match(/^##\s+Goals/i)) {
      inGoals = true;
      continue;
    }
    if (inGoals) {
      if (l.match(/^##\s+/)) break;
      goals += l + "\n";
    }
    const tfMatch = l.match(/\bTarget Files:\s*(.*)/i);
    if (tfMatch) {
      targetFiles = tfMatch[1]
        .split(/,|;/)
        .map((s) => s.trim())
        .filter(Boolean);
    }
  }
  return { goals: goals.trim(), targetFiles, title };
}

/**
 * Description placeholder
 * @author Adminbot
 *
 * @export
 * @param {string[]} changed
 * @param {PlanCandidate} cand
 * @returns {number}
 */
export function scoreCandidate(changed: string[], cand: PlanCandidate): number {
  let score = 0;
  // path prefix boost
  for (const cf of cand.targetFiles ?? []) {
    for (const ch of changed) {
      if (ch.startsWith(cf) || ch.startsWith(cf.replaceAll("\\", "/"))) {
        score += 0.35;
        break;
      }
    }
  }
  // token overlap between changed paths and goals/title
  const text = ((cand.title ?? "") + " " + (cand.goals ?? "")).toLowerCase();
  const tokens = new Set(text.split(/[^a-z0-9]+/).filter(Boolean));
  let overlap = 0;
  let total = 0;
  for (const ch of changed) {
    const parts = ch
      .toLowerCase()
      .split(/[^a-z0-9]+/)
      .filter(Boolean);
    for (const p of parts) {
      total++;
      if (tokens.has(p)) overlap++;
    }
  }
  const tokenScore = total > 0 ? (overlap / total) * 0.5 : 0;
  score = Math.min(1, score + tokenScore);
  return score;
}

/**
 * Description placeholder
 * @author Adminbot
 *
 * @async
 * @returns {Promise<string[]>}
 */
async function getChangedFilesFromGit(): Promise<string[]> {
  try {
    const out = execSync("git diff --name-only --staged", {
      encoding: "utf8",
    }).trim();
    if (!out) return [];
    return out
      .split(/\r?\n/)
      .map((s) => s.trim())
      .filter(Boolean);
  } catch {
    return [];
  }
}

/**
 * Description placeholder
 * @author Adminbot
 *
 * @async
 * @param {string} [base="origin/main"]
 * @returns {unknown}
 */
async function getChangedFilesFromRange(base = "origin/main") {
  try {
    const out = execSync(`git diff --name-only ${base}...HEAD`, {
      encoding: "utf8",
    }).trim();
    if (!out) return [];
    return out
      .split(/\r?\n/)
      .map((s) => s.trim())
      .filter(Boolean);
  } catch {
    return [];
  }
}

/**
 * Description placeholder
 * @author Adminbot
 *
 * @async
 * @returns {*}
 */
async function main() {
  const args = process.argv.slice(2);
  const ci = args.includes("--ci");
  const baseIdx = args.indexOf("--base");
  const base = baseIdx >= 0 ? args[baseIdx + 1] : "origin/main";

  let changed: string[] = [];
  if (ci) {
    changed = await getChangedFilesFromRange(base);
  } else {
    changed = await getChangedFilesFromGit();
  }

  if (changed.length <= 7) {
    console.log("Changed files <= 7 — no plan required.");
    process.exit(0);
  }

  // find candidate plans
  const planFiles = await globby(
    [".opencode/commands/*.plan.md", ".cursor/plans/*.plan.md"],
    { gitignore: true },
  );
  const candidates: PlanCandidate[] = [];
  for (const p of planFiles) {
    try {
      const parsed = readPlanFile(p);
      candidates.push({
        file: p,
        goals: parsed.goals,
        targetFiles: parsed.targetFiles,
        title: parsed.title,
      });
    } catch {
      // ignore
    }
  }

  // score candidates
  const scored: PlanCandidate[] = candidates.map((c) => ({
    ...c,
    score: scoreCandidate(changed, c),
  }));
  const shown = scored
    .filter((s) => (s.score ?? 0) >= 0.4)
    .sort((a, b) => (b.score ?? 0) - (a.score ?? 0));

  if (!ci) {
    // Interactive flow
    console.log(
      `Detected ${changed.length} changed files — exceeding threshold (7).`,
    );
    if (shown.length === 0) {
      console.log("No candidate plans found. Scaffolding a new plan draft.");
      const suggested = scaffoldNewPlan(changed);
      await openEditorAndSave(suggested);
      console.log(
        "New plan draft created. Please commit it to include in your PR.",
      );
      process.exit(0);
    }

    console.log("Candidate plans:");
    const choices = shown.map((s, i) => ({
      name: `${path.basename(s.file)} — score:${(s.score ?? 0).toFixed(2)} — ${s.title ?? "(no title)"}`,
      value: i,
    }));
    choices.push({ name: "Scaffold new plan", value: -1 });
    const ans = await inquirer.prompt([
      {
        choices,
        message: "Select a plan to merge into or scaffold new:",
        name: "pick",
        type: "list",
      },
    ]);
    const pick = ans.pick as number;
    if (pick === -1) {
      const suggested = scaffoldNewPlan(changed);
      await openEditorAndSave(suggested);
      console.log("New plan draft created. Please commit it.");
      process.exit(0);
    }
    const candidate = shown[pick];
    const merged = mergeIntoPlan(candidate.file, changed);
    await openEditorAndSave(merged);
    console.log(
      `Merged draft created at ${merged}. Please commit to include in your PR.`,
    );
    process.exit(0);
  } else {
    // CI flow: produce report and exit with code 0 in pilot mode
    if (shown.length === 0) {
      console.log(
        "[CI] No candidate plan found for large change. Please run 'npm run plan:ensure' locally to scaffold a plan.",
      );
      // in pilot mode we warn — exit 0
      process.exit(0);
    }
    const top = shown[0];
    if ((top.score ?? 0) >= 0.8) {
      console.log(
        `[CI] High-confidence candidate found: ${top.file} (score=${top.score}).`,
      );
      // write merged draft to artifact for maintainer to inspect
      const mergedPath = mergeIntoPlan(top.file, changed);
      console.log(
        `[CI] Merged draft created at ${mergedPath} (artifact). Please review and commit.`,
      );
      process.exit(0);
    }
    console.log(
