#!/usr/bin/env node
/**
 * generate-htpasswd.ts - Generate htpasswd for Traefik
 * TODO: Add bcrypt-based fallback if openssl missing
 */
import fs from "fs";
import path from "path";

import { parseCli, printDryRunResult } from "../utils/cli";

/**
 * Description placeholder
 * @author Adminbot
 *
 * @type {*}
 */
const SCRIPT_DIR = path.dirname(new URL(import.meta.url).pathname);
/**
 * Description placeholder
 * @author Adminbot
 *
 * @type {*}
 */
const AUTH_DIR = path.join(
  SCRIPT_DIR,
  "..",
  "..",
  "compose",
  "traefik",
  "auth",
);
/**
 * Description placeholder
 * @author Adminbot
 *
 * @type {*}
 */
const HTPASSWD_FILE = path.join(AUTH_DIR, "htpasswd");

/**
 * Description placeholder
 * @author Adminbot
 *
 * @type {{ readonly dryRun: any; readonly apply: any; readonly verbose: any; readonly help: any; readonly args: any; }}
 */
const cli = parseCli();
/**
 * Description placeholder
 * @author Adminbot
 *
 * @type {{}}
 */
const args = cli.args._ as string[];
/**
 * Description placeholder
 * @author Adminbot
 *
 * @type {"admin"}
 */
const DEFAULT_USER = "admin";
/**
 * Description placeholder
 * @author Adminbot
 *
 * @type {"admin"}
 */
const DEFAULT_PASS = "admin";
/**
 * Description placeholder
 * @author Adminbot
 *
 * @type {*}
 */
const USERNAME = args && args[0] ? args[0] : DEFAULT_USER;
/**
 * Description placeholder
 * @author Adminbot
 *
 * @type {*}
 */
const PASSWORD =
  args && args[1] ? args[1] : process.env.PASSWORD || DEFAULT_PASS;

if (cli.dryRun) {
  printDryRunResult(
    `Would create htpasswd at ${HTPASSWD_FILE} for user ${USERNAME}`,
    { user: USERNAME },
  );
  process.exit(0);
}

fs.mkdirSync(AUTH_DIR, { recursive: true });

try {
  // Prefer system htpasswd or openssl, else use bcryptjs fallback
  const { spawnSync } = await import("child_process");
  if (spawnSync("htpasswd", ["-v"]).status === 0) {
    const proc = spawnSync("htpasswd", ["-Bc", HTPASSWD_FILE, USERNAME], {
      input: PASSWORD + "\n",
      stdio: "pipe",
    } as any);
    if (proc.status !== 0) throw new Error("htpasswd failed");
  } else if (spawnSync("openssl", ["version"]).status === 0) {
    const res = spawnSync("openssl", ["passwd", "-apr1", PASSWORD], {
      encoding: "utf8",
    });
    fs.writeFileSync(HTPASSWD_FILE, `${USERNAME}:${res.stdout}`);
  } else {
    const bcrypt = require("bcryptjs");
    const salt = bcrypt.genSaltSync(10);
    const hash = bcrypt.hashSync(PASSWORD, salt);
    fs.writeFileSync(HTPASSWD_FILE, `${USERNAME}:${hash}\n`, "utf8");
  }
  fs.chmodSync(HTPASSWD_FILE, 0o600);
  console.log(`Created: ${HTPASSWD_FILE}`);
} catch (err) {
  console.error(err);
  process.exit(1);
}

#!/usr/bin/env node
/**
 * Description: Diagnose common git issues and optionally fix index.lock and run `git add -A` on Unix-like systems.
 * CreatedBy: convert-scripts (fixer batch 1)
 * TODO: add macOS-specific checks
 */
import { spawnSync } from "child_process";
import fs from "fs";
import readline from "readline";

/**
 * Description placeholder
 * @author Adminbot
 *
 * @param {string} cmd
 * @param {string[]} args
 * @returns {{ code: any; stdout: any; stderr: any; }}
 */
function capture(cmd: string, args: string[]) {
  const r = spawnSync(cmd, args, { encoding: "utf8" });
  return {
    code: r.status ?? 0,
    stderr: r.stderr ?? "",
    stdout: r.stdout ?? "",
  };
}

/**
 * Description placeholder
 * @author Adminbot
 *
 * @async
 * @param {string} question
 * @returns {unknown}
 */
async function promptYesNo(question: string) {
  const rl = readline.createInterface({
    input: process.stdin,
    output: process.stdout,
  });
  return new Promise<boolean>((resolve) => {
    rl.question(question + " (y/N): ", (ans) => {
      rl.close();
      resolve(/^y(es)?$/i.test(ans.trim()));
    });
  });
}

/**
 * Description placeholder
 * @author Adminbot
 *
 * @async
 * @returns {*}
 */
async function main() {
  const which = capture("which", ["git"]);
  if (which.code !== 0) {
    console.error("git not found in PATH");
    process.exit(1);
  }

  const status = capture("git", ["status", "--porcelain"]);
  console.log("git status --porcelain output:\n", status.stdout);

  const lockPath = ".git/index.lock";
  if (fs.existsSync(lockPath)) {
    console.log("Detected .git/index.lock");
    // Try ps to find Git processes; fallback to pgrep if available
    let running = false;
    const ps = capture("ps", ["-ef"]);
    if (ps.code === 0) {
      running = /git/i.test(ps.stdout + ps.stderr);
    } else {
      const pg = capture("pgrep", ["-a", "git"]);
      running = pg.code === 0 && pg.stdout.trim().length > 0;
    }
    if (running)
      console.log(
        "Found running git-related processes; recommend closing them before removing index.lock",
      );
    const ok = await promptYesNo("Remove .git/index.lock now?");
    if (ok) {
      try {
        fs.unlinkSync(lockPath);
        console.log("Removed .git/index.lock");
      } catch (err) {
        console.error("Failed to remove lock:", err);
        process.exit(2);
      }
    }
  }

  const add = spawnSync("git", ["add", "-A"], { encoding: "utf8" });
  if (add.stdout) process.stdout.write(add.stdout);
  if (add.stderr) process.stderr.write(add.stderr);
  const code = add.status ?? 0;
  if (code !== 0) {
    console.error(
      "git add failed. Suggestions:\n - Check for locked index or file permissions.\n - Run 'git status' to inspect changes.\n - Try removing .git/index.lock if safe.",
    );
  }
  process.exit(code);
}

if (require.main === module)
  main().catch((err) => {
    console.error(err);
    process.exit(1);
  });

