  run("mkdir", ["-p", "/app/node_modules", "/home/app/.npm"]);
  // chown may fail in some environments - ignore non-zero exit
  try {
    spawnSync(
      "chown",
      ["-R", "app:app", "/app/node_modules", "/home/app/.npm"],
      { stdio: "inherit" },
    );
  } catch {
    // ignore
  }

  run("npm", [
