#!/usr/bin/env tsx
import { execa } from "execa";
import { promises as fs } from "fs";
import path from "path";

// Heuristic runner: parse test-browser-report.txt for failing test file paths
// and re-run them with vitest. Dry-run by default; pass --apply to execute.

/**
 * Description placeholder
 * @author Adminbot
 *
 * @type {"test-browser-report.txt"}
 */
const REPORT = "test-browser-report.txt";

/**
 * Description placeholder
 * @author Adminbot
 *
 * @param {string} content
 * @returns {string[]}
 */
function extractFilesFromReport(content: string): string[] {
  const files = new Set<string>();
  const lines = content.split(/\r?\n/);
  for (const l of lines) {
    // common vitest/jest style: "FAIL path/to/file.test.ts" or "at path/to/file.test.ts"
    // Use explicit space class to avoid super-linear backtracking in regex
    // Avoid complex quantified whitespace patterns; split by whitespace and
    // check the typical vitest fail line format: "FAIL <path>"
    const parts = l.trim().split(/\s+/);
    if (parts.length > 1 && parts[0].toUpperCase() === "FAIL") {
      const candidate = parts[1];
      if (/(.+\.(test|spec)\.(ts|tsx|js|jsx))$/i.test(candidate))
        files.add(candidate);
    }
    // fallback: lines that look like file path with .test.
    const m2 = l.match(/(tests?\/.*\.(test|spec)\.(ts|tsx|js|jsx))/i);
    if (m2) files.add(m2[1]);
  }
  return Array.from(files);
}

/**
 * Description placeholder
 * @author Adminbot
 *
 * @async
 * @param {string[]} files
 * @param {boolean} apply
 * @returns {*}
 */
async function runVitestOnFiles(files: string[], apply: boolean) {
  if (files.length === 0) {
    console.log("No failing test files detected in report.");
    return;
  }
  console.log("Targeted test files:", files);
  const cmd = "npx";
  const args = ["vitest", "--config=vitest.config.ts", "run", ...files];
  if (!apply) {
    console.log("Dry-run: would run:", `${cmd} ${args.join(" ")}`);
    return;
  }

  const p = execa(cmd, args, { shell: true, stdio: "inherit" });
  await p;
}

/**
 * Description placeholder
 * @author Adminbot
 *
 * @async
 * @returns {*}
 */
async function main() {
  const argv = process.argv.slice(2);
  const apply = argv.includes("--apply");

  try {
    const p = path.resolve(process.cwd(), REPORT);
    const content = await fs.readFile(p, "utf8");
    const files = extractFilesFromReport(content).map((f) =>
      path.resolve(process.cwd(), f),
    );
    await runVitestOnFiles(files, apply);
  } catch (err: any) {
    console.warn(`Could not read ${REPORT}:`, err.message || String(err));
    console.log(
      "You can pass explicit file paths: npx tsx scripts/utils/ci-helpers/targeted-test-runner.ts path/to/file.test.ts --apply",
    );
    // also support explicit files
    const provided = argv.filter((a) => a !== "--apply");
    if (provided.length > 0) {
      await runVitestOnFiles(
        provided.map((p) => path.resolve(process.cwd(), p)),
        apply,
      );
    }
  }
}

main().catch((e) => {
  console.error(e);
  process.exit(1);
});

/**
 * Helper to resolve a database connection string for scripts.
 * Prefer validated config via lib/env, but fall back to process.env for
 * ad-hoc local runs. Centralizing this logic keeps eslint disables in one place.
 */
import type { Environment } from "@/lib/env";

/**
 * Description placeholder
 * @author Adminbot
 *
 * @export
 * @async
 * @returns {Promise<string>}
 */
export async function getConnectionString(): Promise<string> {
  try {
    // Dynamic import avoids app-config validation side-effects at module load time
    const imported = (await import("@/lib/env")) as { env: Environment };
    const env = imported.env as Partial<Environment> & Record<string, unknown>;
    const conn =
      (env.DATABASE_URL as string | undefined) ??
      // Some environments expose NEON_DATABASE_URL as an alternate name
      (process.env.NEON_DATABASE_URL as string | undefined);
    if (conn) return conn as string;
  } catch {
    // lib/env may intentionally throw in some ad-hoc environments; fall back.
  }

  // Local fallback to process.env for one-off script runs.
  // eslint-disable-next-line n/no-process-env
  const fallback = process.env.DATABASE_URL ?? process.env.NEON_DATABASE_URL;
  if (fallback) return fallback;

  throw new Error("DATABASE_URL / NEON_DATABASE_URL is not set");
}

#!/usr/bin/env node
/* eslint-disable n/no-process-env, no-console */
/** scripts/utils/io.ts
 *
 * Minimal centralized IO helper for scripts dry-run migration.
 * - Honors CLI --dry-run / -n precedence, DRY_RUN env, and globalThis.__SCRIPTS_DRY_RUN
 * - Provides writeFile, mkdirp, removeFile helpers that log dry-run actions and mask secrets
 * - Designed for use by scripts/generate/* and other migration targets
 */

import fs from "fs";
import path from "path";

/**
 * IO helper options
 *
 * @export
 * @interface IoOptions
 */
export interface IoOptions {
  /**
   * Description placeholder
   * @author Adminbot
   *
   * @type {?boolean}
   */
  dryRun?: boolean;
  /**
   * Description placeholder
   * @author Adminbot
   *
   * @type {?boolean}
   */
  yes?: boolean; // for destructive ops
  /**
   * Description placeholder
   * @author Adminbot
   *
   * @type {?boolean}
   */
  json?: boolean; // emit machine-readable JSON lines when true
}

/**
 * Check CLI flags / env for dry-run semantics
 *
 * @param {*} [argv=process.argv]
 * @returns {boolean}
 */
function isDryRunFlagSet(argv = process.argv): boolean {
  if (argv.includes("--dry-run") || argv.includes("-n")) return true;
  // Prefer lib/env when available to centralize configuration, fall back to process.env
  try {
    // Use require to avoid import-time validation side-effects in scripts

    const { env } = require("@/lib/env") as any;
    if (env && (env.DRY_RUN === "true" || env.DRY_RUN === "1")) return true;
  } catch {
    // fall back to direct process.env when lib/env is not available
  }

  if (process.env["DRY_RUN"] === "true" || process.env["DRY_RUN"] === "1")
    return true;
  const globalDry = (globalThis as any).__SCRIPTS_DRY_RUN;
  if (globalDry === true || globalDry === "true" || globalDry === "1")
    return true;
  return false;
}

/**
 * Shorten content for logging preview
 *
 * @param {string} content
 * @param {number} [max=200]
 * @returns {string}
 */
function maskPreview(content: string, max = 200) {
  if (!content) return "";
  const preview = content.slice(0, max).replaceAll("\n", "\\n");
  return preview + (content.length > max ? "..." : "");
}

/**
 * Structured logging helper for scripts
 *
 * @param {string} action
 * @param {Record<string, unknown>} details
 * @param {boolean} [json=false]
 */
function log(action: string, details: Record<string, unknown>, json = false) {
  if (json) {
    // one-line JSON for machine parsing
    // avoid printing full content in JSON; include preview
    const out = { action, ...details } as any;
    if (typeof out.content === "string")
      out.content = maskPreview(out.content as string, 200);
    console.log(JSON.stringify(out));
  } else {
    console.warn(
      `${action}: ${Object.entries(details)
        .map(([k, v]) => `${k}=${String(v)}`)
        .join(" ")}`,
    );
  }
}

/**
 * Ensure a directory exists (with dry-run support)
 *
 * @export
 * @async
 * @param {string} targetPath
 * @param {IoOptions} [opts={}]
 */
export async function mkdirp(targetPath: string, opts: IoOptions = {}) {
  const dry = opts.dryRun ?? isDryRunFlagSet();
  if (dry) {
    log(
      "[dry-run] mkdirp",
      { path: path.relative(process.cwd(), targetPath) },
      opts.json ?? false,
    );
    return;
  }
  await fs.promises.mkdir(targetPath, { recursive: true });
  log(
    "mkdir",
    { path: path.relative(process.cwd(), targetPath) },
    opts.json ?? false,
  );
}

/**
 * Write a file, creating directories as needed (dry-run aware)
 *
 * @export
 * @async
 * @param {string} filePath
 * @param {string} content
 * @param {IoOptions} [opts={}]
 */
export async function writeFile(
  filePath: string,
  content: string,
  opts: IoOptions = {},
) {
  const dry = opts.dryRun ?? isDryRunFlagSet();

  if (dry) {
    log(
      "[dry-run] writeFile",
      {
        content: maskPreview(content),
        path: path.relative(process.cwd(), filePath),
      },
      opts.json ?? false,
    );
    return;
  }

  await fs.promises.mkdir(path.dirname(filePath), { recursive: true });
  await fs.promises.writeFile(filePath, content, "utf8");
  log(
    "writeFile",
    { path: path.relative(process.cwd(), filePath), size: content.length },
    opts.json ?? false,
  );
}

/**
 * Remove a file (supports destructive gating and dry-run)
 *
 * @export
 * @async
 * @param {string} filePath
 * @param {IoOptions} [opts={}]
 */
export async function removeFile(filePath: string, opts: IoOptions = {}) {
  const dry = opts.dryRun ?? isDryRunFlagSet();
  const requireYes = process.env["RUN_DESTRUCTIVE"] === "true";
  if (requireYes && !opts.yes) {
    // If destructive gating is enabled via env, require opts.yes true
    if (dry) {
      log(
        "[dry-run] removeFile (gated)",
        { path: path.relative(process.cwd(), filePath) },
        opts.json ?? false,
      );
      return;
    }
    throw new Error(
      "Destructive operations require RUN_DESTRUCTIVE=true and --yes flag",
    );
  }

  if (dry) {
    log(
      "[dry-run] removeFile",
      { path: path.relative(process.cwd(), filePath) },
      opts.json ?? false,
    );
    return;
  }

  await fs.promises.rm(filePath, { force: true });
  log(
    "removeFile",
    { path: path.relative(process.cwd(), filePath) },
    opts.json ?? false,
  );
}

/**
 * Check dry-run status for callers
 *
 * @export
 * @param {?IoOptions} [opts]
 * @returns {boolean}
 */
export function isDryRun(opts?: IoOptions) {
  return opts?.dryRun ?? isDryRunFlagSet();
}

/**
 * Exported script IO helpers
 */
const exported = { isDryRun, mkdirp, removeFile, writeFile };
export default exported;

